package com.PoorMensKindle.android.ui.screens

import android.content.Intent
import android.content.IntentFilter
import android.net.Uri
import android.os.BatteryManager
import android.view.ActionMode
import androidx.core.net.toUri
import android.view.Menu
import android.view.MenuItem
import android.webkit.WebView
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.font.FontFamily
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.compose.ui.viewinterop.AndroidView
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.delay
import kotlinx.coroutines.isActive
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import nl.siegmann.epublib.domain.Book
import nl.siegmann.epublib.epub.EpubReader
import okhttp3.OkHttpClient
import okhttp3.Request
import org.json.JSONArray
import org.json.JSONObject
import org.jsoup.Jsoup
import java.time.LocalTime
import java.time.ZoneId
import java.time.format.DateTimeFormatter
import kotlin.math.ceil

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun LocalReadScreen(
    fileUriString: String,
    onNavigateBack: () -> Unit
) {
    val context = LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    val fileUri = fileUriString.toUri()

    // EPUB State
    var epubBook by remember { mutableStateOf<Book?>(null) }
    var currentChapterIndex by remember { mutableIntStateOf(0) }
    var totalChapters by remember { mutableIntStateOf(0) }

    // UI State
    var chapterHtml by remember { mutableStateOf("Loading book...") }
    var chapterTitle by remember { mutableStateOf("Opening...") }
    var errorMessage by remember { mutableStateOf("") }

    // Live Footer State
    var currentTime by remember { mutableStateOf("") }
    var batteryStatus by remember { mutableStateOf("--%") }
    var wordCount by remember { mutableIntStateOf(0) }
    var timeRemaining by remember { mutableStateOf("< 1 min left") }

    // Smart Tools State
    var toolDialogTitle by remember { mutableStateOf("") }
    var toolDialogContent by remember { mutableStateOf("") }
    var isLoadingTool by remember { mutableStateOf(false) }
    val publicApiClient = remember { OkHttpClient() }

    // Smart Tool Fetcher
    fun fetchSmartTool(type: Int, rawQuery: String) {
        val query = rawQuery.replace("\"", "").trim()
        if (query.isEmpty()) return

        isLoadingTool = true
        toolDialogContent = "Fetching..."
        toolDialogTitle = when (type) {
            1 -> " Dictionary: $query"
            2 -> " Hebrew Translation"
            else -> " Wikipedia: $query"
        }

        coroutineScope.launch(Dispatchers.IO) {
            try {
                val url = when (type) {
                    1 -> "https://api.dictionaryapi.dev/api/v2/entries/en/$query"
                    2 -> "https://api.mymemory.translated.net/get?q=$query&langpair=en|he"
                    else -> "https://en.wikipedia.org/api/rest_v1/page/summary/$query"
                }

                val response = publicApiClient.newCall(Request.Builder().url(url).build()).execute()
                val responseBody = response.body?.string() ?: ""

                val result = if (response.isSuccessful && responseBody.isNotEmpty()) {
                    when (type) {
                        1 -> JSONArray(responseBody).getJSONObject(0).getJSONArray("meanings")
                            .getJSONObject(0).getJSONArray("definitions").getJSONObject(0).getString("definition")
                        2 -> JSONObject(responseBody).getJSONObject("responseData").getString("translatedText")
                        else -> JSONObject(responseBody).getString("extract")
                    }
                } else "No results found."

                withContext(Dispatchers.Main) {
                    toolDialogContent = result
                    isLoadingTool = false
                }
            } catch (e: Exception) {
                withContext(Dispatchers.Main) {
                    toolDialogContent = "Error: ${e.localizedMessage}"
                    isLoadingTool = false
                }
            }
        }
    }

    // 1. Load the EPUB File initially
    LaunchedEffect(fileUri) {
        try {
            withContext(Dispatchers.IO) {
                val inputStream = context.contentResolver.openInputStream(fileUri)
                // --- FIX 1: Null check for InputStream ---
                if (inputStream == null) {
                    errorMessage = "Could not open file stream."
                    return@withContext
                }

                val book = EpubReader().readEpub(inputStream)
                epubBook = book
                totalChapters = book.spine.size()
                chapterTitle = book.title ?: "Unknown Title"
            }
        } catch (e: Exception) {
            errorMessage = "Failed to parse EPUB: ${e.message}"
        }
    }

    // 2. Extract and render the current chapter HTML (with Base64 Image Injection)
    LaunchedEffect(epubBook, currentChapterIndex) {
        val book = epubBook ?: return@LaunchedEffect
        try {
            val spineRef = book.spine.spineReferences[currentChapterIndex]
            val resource = spineRef.resource
            val rawHtml = String(resource.data)

            // Parse the HTML using JSoup to manipulate the DOM
            val doc = Jsoup.parse(rawHtml)
            val chapterHref = resource.href

            // --- Intercept and convert all images to Base64 ---
            val images = doc.select("img")
            for (img in images) {
                var src = img.attr("src")
                src = java.net.URLDecoder.decode(src, "UTF-8") // Clean up %20 spaces

                // Try to find the image resource inside the EPUB
                var imageResource = book.resources.getByHref(src)

                // If direct match fails, resolve the relative path (e.g., "../images/pic.jpg")
                if (imageResource == null) {
                    try {
                        val baseUri = java.net.URI(chapterHref)
                        val resolvedUri = baseUri.resolve(src).toString()
                        imageResource = book.resources.getByHref(resolvedUri)
                    } catch (e: Exception) {
                        // URI resolution failed, leave imageResource as null
                    }
                }

                // If we found the image in the EPUB, convert it to a Base64 URI
                if (imageResource != null) {
                    val imgData = imageResource.data
                    val base64Img = android.util.Base64.encodeToString(imgData, android.util.Base64.NO_WRAP)
                    val mimeType = imageResource.mediaType?.name ?: "image/jpeg"

                    // Replace the broken relative path with the raw Base64 data
                    img.attr("src", "data:$mimeType;base64,$base64Img")
                }
            }

            // Calculate Word Count and Time Remaining from the clean text
            val plainText = doc.text()
            wordCount = plainText.split("\\s+".toRegex()).size
            val minutes = ceil(wordCount / 225.0).toInt()
            timeRemaining = if (minutes > 1) "$minutes mins left" else "< 1 min left"

            // Inject Dark Mode CSS and the modified JSoup HTML body
            chapterHtml = """
                <!DOCTYPE html>
                <html>
                <head>
                    <meta name="viewport" content="width=device-width, initial-scale=1.0">
                    <style>
                        body { 
                            font-family: 'Palatino', serif; 
                            font-size: 18px; 
                            padding: 20px 15px; 
                            color: #d4d4d4; 
                            background-color: #2b2b2b; 
                            line-height: 1.6; 
                            margin: 0;
                        }
                        /* Added image styling to ensure large images fit on a phone screen */
                        img { max-width: 100%; height: auto; display: block; margin: 10px auto; border-radius: 8px; }
                        p { margin-bottom: 1em; }
                    </style>
                </head>
                <body>
                    ${doc.body().html()}
                </body>
                </html>
            """.trimIndent()
        } catch (e: Exception) {
            chapterHtml = "<div style='color: #ff6b6b;'>Error loading chapter: ${e.message}</div>"
        }
    }

    // Live Clock & Battery Loop
    LaunchedEffect(Unit) {
        var ticks = 0
        while (isActive) {
            currentTime = LocalTime.now(ZoneId.of("Asia/Jerusalem")).format(DateTimeFormatter.ofPattern("HH:mm"))
            if (ticks % 60 == 0) {
                val intent = context.registerReceiver(null, IntentFilter(Intent.ACTION_BATTERY_CHANGED))
                val level = intent?.getIntExtra(BatteryManager.EXTRA_LEVEL, -1) ?: -1
                val scale = intent?.getIntExtra(BatteryManager.EXTRA_SCALE, -1) ?: -1
                val isCharging = intent?.getIntExtra(BatteryManager.EXTRA_STATUS, -1) in listOf(BatteryManager.BATTERY_STATUS_CHARGING, BatteryManager.BATTERY_STATUS_FULL)
                val pct = if (scale > 0) (level * 100) / scale else 0
                batteryStatus = if (isCharging) "⚡$pct%" else "$pct%"
            }
            ticks++
            delay(1000)
        }
    }

    // Tool Dialog
    if (toolDialogTitle.isNotEmpty()) {
        AlertDialog(
            onDismissRequest = { toolDialogTitle = "" },
            title = { Text(toolDialogTitle, color = Color(0xFF4dd0e1), fontWeight = FontWeight.Bold, fontFamily = FontFamily.Serif) },
            text = {
                if (isLoadingTool) CircularProgressIndicator(color = Color(0xFF4dd0e1))
                else Text(toolDialogContent, color = Color.White, fontSize = 16.sp, fontFamily = FontFamily.Serif)
            },
            confirmButton = { TextButton(onClick = { toolDialogTitle = "" }) { Text("Close", color = Color(0xFF4dd0e1)) } },
            containerColor = Color(0xFF2b2b2b)
        )
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(chapterTitle, fontWeight = FontWeight.Bold) },
                navigationIcon = {
                    TextButton(onClick = onNavigateBack) { Text("◀ Back", color = Color(0xFF4dd0e1), fontWeight = FontWeight.Bold) }
                },
                colors = TopAppBarDefaults.topAppBarColors(containerColor = Color(0xFF1E1E1E), titleContentColor = Color.White)
            )
        },
        bottomBar = {
            BottomAppBar(containerColor = Color(0xFF1E1E1E), modifier = Modifier.height(110.dp)) {
                Column(
                    modifier = Modifier.fillMaxWidth().padding(horizontal = 16.dp, vertical = 8.dp),
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.SpaceBetween
                ) {
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
                        Button(
                            onClick = { if (currentChapterIndex > 0) currentChapterIndex-- },
                            enabled = currentChapterIndex > 0,
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF442694))
                        ) { Text("◀ Prev") }

                        Text("${currentChapterIndex + 1} / ${if(totalChapters == 0) "?" else totalChapters}", color = Color.White, fontWeight = FontWeight.Bold)

                        Button(
                            onClick = { if (currentChapterIndex < totalChapters - 1) currentChapterIndex++ },
                            enabled = currentChapterIndex < totalChapters - 1,
                            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF442694))
                        ) { Text("Next ▶") }
                    }
                    Spacer(modifier = Modifier.height(12.dp))
                    Text("[$currentTime]  [$batteryStatus]  ($timeRemaining)  [Words: $wordCount]", color = Color.LightGray, fontSize = 12.sp, fontFamily = FontFamily.Serif)
                }
            }
        }
    ) { paddingValues ->
        Box(modifier = Modifier.padding(paddingValues).fillMaxSize().background(Color(0xFF2b2b2b))) {
            if (errorMessage.isNotEmpty()) {
                Text(errorMessage, color = Color.Red, modifier = Modifier.align(Alignment.Center).padding(20.dp))
            } else {
                AndroidView(
                    factory = { ctx ->
                        WebView(ctx).apply {
                            settings.javaScriptEnabled = true
                            setBackgroundColor(android.graphics.Color.TRANSPARENT)

                            // --- Smart Context Menu ---
                            customSelectionActionModeCallback = object : ActionMode.Callback {
                                override fun onCreateActionMode(mode: ActionMode?, menu: Menu?): Boolean {
                                    menu?.add(0, 1, 0, " Dictionary")
                                    menu?.add(0, 2, 0, " Translate (HE)")
                                    menu?.add(0, 3, 0, " Wikipedia")
                                    return true
                                }
                                override fun onPrepareActionMode(mode: ActionMode?, menu: Menu?) = false
                                override fun onActionItemClicked(mode: ActionMode?, item: MenuItem?): Boolean {
                                    val id = item?.itemId ?: return false

                                    if (id in 1..3) {
                                        evaluateJavascript("(function(){return window.getSelection().toString()})()") { selection ->
                                            fetchSmartTool(id, selection ?: "")
                                        }
                                        mode?.finish()
                                        return true
                                    }
                                    return false
                                }
                                override fun onDestroyActionMode(mode: ActionMode?) {}
                            }

                            // --- 3. RE-ADDED: Swipe-to-Turn Gesture Detector ---
                            val gestureDetector = android.view.GestureDetector(ctx, object : android.view.GestureDetector.SimpleOnGestureListener() {
                                private val SWIPE_THRESHOLD = 120
                                private val SWIPE_VELOCITY_THRESHOLD = 150

                                override fun onFling(
                                    e1: android.view.MotionEvent?,
                                    e2: android.view.MotionEvent,
                                    velocityX: Float,
                                    velocityY: Float
                                ): Boolean {
                                    if (e1 == null) return false
                                    val diffX = e2.x - e1.x
                                    val diffY = e2.y - e1.y

                                    // Check if it's a horizontal swipe rather than a vertical scroll
                                    if (Math.abs(diffX) > Math.abs(diffY)) {
                                        if (Math.abs(diffX) > SWIPE_THRESHOLD && Math.abs(velocityX) > SWIPE_VELOCITY_THRESHOLD) {
                                            if (diffX > 0) {
                                                // Swipe Right -> Previous Chapter
                                                if (currentChapterIndex > 0) currentChapterIndex--
                                            } else {
                                                // Swipe Left -> Next Chapter
                                                if (currentChapterIndex < totalChapters - 1) currentChapterIndex++
                                            }
                                            return true // Event consumed
                                        }
                                    }
                                    return false
                                }
                            })

                            // Attach the gesture detector to the WebView
                            setOnTouchListener { _, event ->
                                gestureDetector.onTouchEvent(event)
                                false // Return false to let the WebView continue handling vertical scrolling
                            }
                        }
                    },
                    update = { webView ->
                        webView.loadDataWithBaseURL(null, chapterHtml, "text/html", "UTF-8", null)
                    },
                    modifier = Modifier.fillMaxSize()
                )
            }
        }
    }
}

